"use client";

import * as React from "react";
import {
  ListCard,
  Badge,
  Tag,
  Icon,
  SearchInput,
  ToggleGroup,
  ToggleGroupItem,
  EmptyState,
  Separator,
} from "@gunjo/ui";
import {
  IconMapPin,
  IconWalk,
  IconMap2,
  IconSearch,
  IconChevronRight,
  IconPlaneDeparture,
  IconPlaneArrival,
  IconDiscount2,
} from "@tabler/icons-react";
import {
  CATEGORIES,
  FACILITIES,
  TERMINAL,
  TERMINALS,
  BOARDING,
  type CategoryId,
  type AreaId,
  type DirectionId,
  type Facility,
  type TerminalId,
} from "./data";
import { CATEGORY_ICON, KIND_ICON } from "./icons";
import { OpenBadge } from "./shared";
import { FacilityDetailSheet } from "./FacilityDetailSheet";

type AreaFilter = "all" | AreaId;

function matchesDirection(f: Facility, dir: DirectionId): boolean {
  return f.direction === dir || f.direction === "both";
}

/** 検索対象テキスト */
function haystack(f: Facility): string {
  return [f.name, f.near, f.floor, f.genre].filter(Boolean).join(" ");
}

export default function AirportGuidePage() {
  const [terminal, setTerminal] = React.useState<TerminalId>(TERMINAL.id);
  const [direction, setDirection] = React.useState<DirectionId>("departure");
  const [area, setArea] = React.useState<AreaFilter>("all");
  const [category, setCategory] = React.useState<CategoryId>("all");
  const [query, setQuery] = React.useState("");
  const [selected, setSelected] = React.useState<Facility | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);

  const open = React.useCallback((f: Facility) => {
    setSelected(f);
    setSheetOpen(true);
  }, []);

  const results = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return FACILITIES.filter((f) => {
      if (!matchesDirection(f, direction)) return false;
      if (area !== "all" && f.area !== area) return false;
      if (category !== "all" && f.category !== category) return false;
      if (q && !haystack(f).toLowerCase().includes(q)) return false;
      return true;
    }).sort((a, b) => a.walkMin - b.walkMin);
  }, [direction, area, category, query]);

  // 「あなたの搭乗口」を一覧の文脈で見つけやすく
  const yourGate = React.useMemo(
    () => FACILITIES.find((f) => f.id === `gate-${BOARDING.gate}`) ?? null,
    []
  );

  return (
    <main className="mx-auto w-full max-w-md bg-background pb-10">
      {/* ===== ヘッダー ===== */}
      <header className="sticky top-0 z-20 border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <div className="px-4 pb-3 pt-4">
          <p className="text-xs text-muted-foreground">{TERMINAL.airport}</p>
          <h1 className="mt-0.5 text-xl font-bold tracking-tight">
            ターミナルガイド
          </h1>

          {/* ターミナル切替（第1/第2/第3） */}
          <div
            className="mt-3"
            role="group"
            aria-label="ターミナルを選択"
          >
            <ToggleGroup
              type="single"
              value={terminal}
              onValueChange={(v) => v && setTerminal(v as TerminalId)}
              disallowEmpty
              variant="outline"
              className="w-full justify-start gap-2"
            >
              {TERMINALS.map((t) => (
                <ToggleGroupItem
                  key={t.id}
                  value={t.id}
                  size="lg"
                  aria-label={`${t.label}ターミナル ${t.sub}`}
                  className="flex-1 flex-col gap-0 py-1 leading-tight"
                >
                  <span className="text-sm font-semibold">{t.label}</span>
                  <span className="text-[10px] font-normal opacity-70">
                    {t.sub}
                  </span>
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>

          {/* 出発/到着 切替 */}
          <div className="mt-2" role="group" aria-label="出発・到着を選択">
            <ToggleGroup
              type="single"
              value={direction}
              onValueChange={(v) => v && setDirection(v as DirectionId)}
              disallowEmpty
              className="w-full gap-1"
            >
              <ToggleGroupItem value="departure" className="flex-1 gap-1.5">
                <IconPlaneDeparture className="size-4" aria-hidden />
                出発
              </ToggleGroupItem>
              <ToggleGroupItem value="arrival" className="flex-1 gap-1.5">
                <IconPlaneArrival className="size-4" aria-hidden />
                到着
              </ToggleGroupItem>
            </ToggleGroup>
          </div>
        </div>

        {/* カテゴリ・チップ（横スクロール） */}
        <nav aria-label="施設カテゴリ" className="relative">
          <div className="overflow-x-auto pb-3 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
            <ToggleGroup
              type="single"
              value={category}
              onValueChange={(v) => v && setCategory(v as CategoryId)}
              disallowEmpty
              variant="outline"
              className="w-max flex-nowrap justify-start gap-2 px-4"
            >
              {CATEGORIES.map((c) => (
                <ToggleGroupItem
                  key={c.id}
                  value={c.id}
                  className="shrink-0 gap-1.5 rounded-full"
                  aria-label={`${c.label}で絞り込む`}
                >
                  <Icon icon={CATEGORY_ICON[c.id]} size="sm" />
                  {c.label}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>
        </nav>
      </header>

      {/* ===== 搭乗便バナー（搭乗まで○分） ===== */}
      {yourGate && (
        <button
          type="button"
          onClick={() => open(yourGate)}
          className="mx-4 mt-4 flex w-[calc(100%-2rem)] items-center gap-3 rounded-xl border border-primary/30 bg-primary-subtle px-4 py-3 text-left transition-colors hover:bg-primary-subtle/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label={`あなたの搭乗便 ${BOARDING.flight} ${BOARDING.destination}、搭乗口${BOARDING.gate}番への案内を開く。搭乗まであと${BOARDING.minutesToBoarding}分`}
        >
          <span
            className="flex size-10 shrink-0 items-center justify-center rounded-full bg-primary text-primary-foreground"
            aria-hidden
          >
            <IconPlaneDeparture className="size-5" />
          </span>
          <div className="min-w-0 flex-1">
            <p className="text-xs font-medium text-primary">
              {BOARDING.flight}・{BOARDING.destination}
            </p>
            <p className="truncate text-sm font-semibold text-foreground">
              搭乗口 {BOARDING.gate}番 まで徒歩 約{BOARDING.gateWalkMin}分
            </p>
          </div>
          <div className="shrink-0 text-right">
            <p className="text-lg font-bold leading-none tabular-nums text-primary">
              あと{BOARDING.minutesToBoarding}分
            </p>
            <p className="text-[10px] text-muted-foreground">搭乗開始まで</p>
          </div>
          <IconChevronRight className="size-4 shrink-0 text-muted-foreground" aria-hidden />
        </button>
      )}

      {/* ===== 検索 + エリア絞り込み ===== */}
      <div className="space-y-3 px-4 pt-4">
        <SearchInput
          value={query}
          onValueChange={setQuery}
          placeholder="施設・店舗名で検索（例：ラウンジ、そば）"
          aria-label="施設を検索"
        />

        <div className="flex items-center gap-2" role="group" aria-label="エリアで絞り込む">
          <ToggleGroup
            type="single"
            value={area}
            onValueChange={(v) => v && setArea(v as AreaFilter)}
            disallowEmpty
            size="sm"
            className="gap-1"
          >
            <ToggleGroupItem value="all" size="sm">
              全エリア
            </ToggleGroupItem>
            <ToggleGroupItem value="airside" size="sm">
              制限エリア内
            </ToggleGroupItem>
            <ToggleGroupItem value="landside" size="sm">
              制限エリア外
            </ToggleGroupItem>
          </ToggleGroup>
        </div>
      </div>

      {/* ===== マップのスタブ ===== */}
      <section className="px-4 pt-4" aria-label="ターミナルマップ">
        <button
          type="button"
          className="relative flex h-28 w-full items-center justify-center overflow-hidden rounded-xl border border-dashed border-border bg-muted/40 text-muted-foreground transition-colors hover:bg-muted/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label="ターミナルマップを開く"
        >
          <span
            aria-hidden
            className="absolute inset-0 bg-[radial-gradient(circle_at_30%_40%,theme(colors.border)_1px,transparent_1.5px)] [background-size:18px_18px] opacity-50"
          />
          <span className="relative flex flex-col items-center gap-1">
            <IconMap2 className="size-6" aria-hidden />
            <span className="text-xs font-medium">
              {TERMINAL.name} フロアマップを開く
            </span>
          </span>
        </button>
      </section>

      {/* ===== 施設一覧 ===== */}
      <section className="px-4 pt-5" aria-label="施設一覧">
        <div className="mb-2 flex items-baseline justify-between">
          <h2 className="text-sm font-semibold text-foreground">
            {CATEGORIES.find((c) => c.id === category)?.label}
          </h2>
          <p className="text-xs text-muted-foreground" aria-live="polite">
            {results.length}件・近い順
          </p>
        </div>

        {results.length === 0 ? (
          <EmptyState
            icon={<IconSearch className="size-6" aria-hidden />}
            title="該当する施設が見つかりません"
            description="カテゴリやエリアの絞り込みを変えてお試しください。"
            headingLevel={3}
          />
        ) : (
          <ul className="space-y-2">
            {results.map((f) => {
              const isYourGate = f.id === `gate-${BOARDING.gate}`;
              return (
                <li key={f.id}>
                  <ListCard
                    onSelect={() => open(f)}
                    selected={selected?.id === f.id && sheetOpen}
                    severity={isYourGate ? "info" : undefined}
                    leading={
                      <span
                        className="flex size-10 items-center justify-center rounded-lg bg-secondary text-foreground"
                        aria-hidden
                      >
                        <Icon icon={KIND_ICON[f.kind]} size="md" />
                      </span>
                    }
                    title={
                      <span className="flex items-center gap-1.5">
                        {f.name}
                        {isYourGate && (
                          <Badge variant="info" className="ml-0.5">
                            搭乗便
                          </Badge>
                        )}
                      </span>
                    }
                    description={
                      <span className="flex items-center gap-1 text-muted-foreground">
                        <IconMapPin className="size-3.5 shrink-0" aria-hidden />
                        <span className="truncate">
                          {f.floor}・{f.near}
                        </span>
                      </span>
                    }
                    tags={
                      <>
                        <OpenBadge state={f.open} />
                        {f.genre && <Tag variant="secondary">{f.genre}</Tag>}
                        {f.dutyFree && (
                          <Badge
                            variant="info"
                            icon={<IconDiscount2 className="size-3" aria-hidden />}
                          >
                            免税
                          </Badge>
                        )}
                        {f.hours && (
                          <span className="text-xs text-muted-foreground">
                            {f.hours}
                          </span>
                        )}
                      </>
                    }
                    meta={
                      <span className="flex flex-col items-end leading-tight">
                        <span className="flex items-center gap-0.5 text-sm font-semibold tabular-nums">
                          <IconWalk className="size-3.5" aria-hidden />
                          {f.walkMin}分
                        </span>
                        <span className="text-[11px] text-muted-foreground tabular-nums">
                          約{f.distanceM}m
                        </span>
                      </span>
                    }
                  />
                </li>
              );
            })}
          </ul>
        )}

        <Separator className="my-5" />
        <p className="px-1 text-center text-[11px] leading-relaxed text-muted-foreground">
          {TERMINAL.name}・{TERMINAL.subtitle}
          <br />
          営業時間・混雑状況は目安です。最新の運航・搭乗口は空港の案内表示をご確認ください。
        </p>
      </section>

      <FacilityDetailSheet
        facility={selected}
        open={sheetOpen}
        onOpenChange={setSheetOpen}
      />
    </main>
  );
}

"use client";

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Badge,
  Tag,
  Icon,
  Button,
  Meter,
  MetadataList,
  RouteStops,
  Separator,
  type RouteStopItem,
} from "@gunjo/ui";
import {
  IconWalk,
  IconMapPin,
  IconClock,
  IconRoute,
  IconArmchair2,
  IconDiscount2,
} from "@tabler/icons-react";
import {
  type Facility,
  type OpenState,
  BOARDING,
  TERMINAL,
} from "./data";
import { KIND_ICON } from "./icons";
import { OpenBadge, areaLabel } from "./shared";

/** 搭乗口への案内ルート（あなたの搭乗便のゲートを開いたときだけ表示） */
const GATE_ROUTE: RouteStopItem[] = [
  { id: "now", title: "現在地（出発フロア中央）", description: "3F", status: "completed" },
  {
    id: "security",
    title: "保安検査場 B",
    description: "手荷物検査。混雑時 約5分",
    status: "current",
  },
  {
    id: "walkway",
    title: "動く歩道（60〜70番方面）",
    description: "「60〜70番ゲート」案内に従って直進",
    status: "pending",
  },
  {
    id: "gate",
    title: `${BOARDING.gate}番搭乗口`,
    description: "突き当たり手前・右側",
    status: "pending",
  },
];

function loungeTone(level: number) {
  if (level >= 75) return "destructive" as const;
  if (level >= 45) return "warning" as const;
  return "success" as const;
}
function loungeLabel(level: number) {
  if (level >= 75) return "混雑";
  if (level >= 45) return "やや混雑";
  return "空いています";
}

export function FacilityDetailSheet({
  facility,
  open,
  onOpenChange,
}: {
  facility: Facility | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}) {
  const isYourGate = facility?.id === `gate-${BOARDING.gate}`;

  const meta = React.useMemo(() => {
    if (!facility) return [];
    const items = [
      {
        label: "場所",
        value: facility.floor,
        icon: <IconMapPin className="size-4" aria-hidden />,
      },
      {
        label: "目印",
        value: facility.near,
      },
      {
        label: "エリア",
        value: areaLabel(facility.area),
      },
      {
        label: "現在地から",
        value: `徒歩 約${facility.walkMin}分・約${facility.distanceM}m`,
        icon: <IconWalk className="size-4" aria-hidden />,
      },
    ];
    if (facility.hours) {
      items.push({
        label: "営業時間",
        value: facility.hours,
        icon: <IconClock className="size-4" aria-hidden />,
      });
    }
    if (facility.genre) items.push({ label: "ジャンル", value: facility.genre });
    return items;
  }, [facility]);

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="max-h-[88vh] overflow-y-auto rounded-t-2xl px-0 pb-0"
      >
        {facility && (
          <>
            <SheetHeader className="px-5 text-left">
              <div className="flex items-start gap-3">
                <span
                  className="flex size-11 shrink-0 items-center justify-center rounded-xl bg-primary-subtle text-primary"
                  aria-hidden
                >
                  <Icon icon={KIND_ICON[facility.kind]} size="lg" />
                </span>
                <div className="min-w-0 flex-1">
                  <SheetTitle className="text-lg leading-tight">
                    {facility.name}
                  </SheetTitle>
                  <SheetDescription className="mt-1">
                    {TERMINAL.name}・{facility.floor}
                  </SheetDescription>
                  <div className="mt-2 flex flex-wrap items-center gap-1.5">
                    <OpenBadge state={facility.open} />
                    {facility.dutyFree && (
                      <Badge
                        variant="info"
                        icon={<IconDiscount2 className="size-3" aria-hidden />}
                      >
                        免税対象
                      </Badge>
                    )}
                    {isYourGate && (
                      <Badge variant="warning">あなたの搭乗口</Badge>
                    )}
                  </div>
                </div>
              </div>
            </SheetHeader>

            {/* 搭乗まで○分（あなたのゲートのとき） */}
            {isYourGate && (
              <div className="mx-5 mt-2 rounded-xl border border-warning-border bg-warning-subtle p-3 text-warning-subtle-foreground">
                <div className="flex items-center justify-between gap-2">
                  <div>
                    <p className="text-xs font-medium opacity-80">
                      {BOARDING.flight}・{BOARDING.destination}
                    </p>
                    <p className="text-sm font-semibold">
                      搭乗開始 {BOARDING.boardingTime}・搭乗口 {BOARDING.gate}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-bold leading-none tabular-nums">
                      あと{BOARDING.minutesToBoarding}分
                    </p>
                    <p className="mt-0.5 text-xs">
                      ゲートまで徒歩 約{BOARDING.gateWalkMin}分
                    </p>
                  </div>
                </div>
              </div>
            )}

            <div className="space-y-5 px-5 py-4">
              {/* 基本情報 */}
              <MetadataList items={meta} layout="horizontal" />

              {/* ラウンジ混雑 */}
              {facility.crowd && (
                <section aria-label="混雑状況">
                  <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold">
                    <IconArmchair2 className="size-4" aria-hidden />
                    混雑状況
                  </h3>
                  <Meter
                    value={facility.crowd.level}
                    max={100}
                    unit="%"
                    tone={loungeTone(facility.crowd.level)}
                    label={`混雑度 ${facility.crowd.level}% — ${loungeLabel(
                      facility.crowd.level
                    )}`}
                  />
                  <p className="mt-1 text-xs text-muted-foreground">
                    現在 {loungeLabel(facility.crowd.level)}
                  </p>
                </section>
              )}

              {/* ラウンジ利用条件 */}
              {facility.loungeAccess && (
                <section aria-label="ご利用条件">
                  <h3 className="mb-2 text-sm font-semibold">ご利用条件</h3>
                  <div className="flex flex-wrap gap-1.5">
                    {facility.loungeAccess.map((a) => (
                      <Tag key={a} variant="outline">
                        {a}
                      </Tag>
                    ))}
                  </div>
                </section>
              )}

              {/* 搭乗口への案内ルート */}
              {isYourGate ? (
                <section aria-label="搭乗口への案内">
                  <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold">
                    <IconRoute className="size-4" aria-hidden />
                    搭乗口への案内
                  </h3>
                  <RouteStops
                    stops={GATE_ROUTE}
                    hideTimes
                    statusLabels={{
                      completed: "現在地",
                      current: "次",
                      pending: "この先",
                    }}
                  />
                </section>
              ) : (
                facility.directions && (
                  <section aria-label="行き方">
                    <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold">
                      <IconRoute className="size-4" aria-hidden />
                      行き方
                    </h3>
                    <ol className="space-y-2">
                      {facility.directions.map((step, i) => (
                        <li key={i} className="flex gap-2.5 text-sm">
                          <span
                            className="flex size-5 shrink-0 items-center justify-center rounded-full bg-secondary text-xs font-semibold tabular-nums"
                            aria-hidden
                          >
                            {i + 1}
                          </span>
                          <span className="text-foreground">{step}</span>
                        </li>
                      ))}
                    </ol>
                  </section>
                )
              )}

              {facility.note && (
                <>
                  <Separator />
                  <p className="text-sm text-muted-foreground">{facility.note}</p>
                </>
              )}
            </div>

            <SheetFooter className="sticky bottom-0 gap-2 border-t bg-background px-5 py-3">
              <Button
                variant="primary"
                className="w-full"
                aria-label={`${facility.name}までの経路をマップで見る`}
              >
                <IconMapPin className="size-4" aria-hidden />
                マップで経路を見る
              </Button>
            </SheetFooter>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
}

export type { OpenState };

import * as React from "react";
import { Badge } from "@gunjo/ui";
import { IconCircleCheck, IconClock, IconLock } from "@tabler/icons-react";
import type { AreaId, OpenState } from "./data";

/** 制限エリア内/外のラベル */
export function areaLabel(area: AreaId): string {
  return area === "airside" ? "制限エリア内（保安検査後）" : "制限エリア外（一般）";
}

/** 営業状態バッジ — 色だけに依存せずアイコン＋テキストで状態を伝える */
export function OpenBadge({ state }: { state?: OpenState }) {
  if (!state) return null;
  switch (state) {
    case "24h":
      return (
        <Badge variant="success" icon={<IconCircleCheck className="size-3" aria-hidden />}>
          24時間
        </Badge>
      );
    case "open":
      return (
        <Badge variant="success" icon={<IconCircleCheck className="size-3" aria-hidden />}>
          営業中
        </Badge>
      );
    case "closing-soon":
      return (
        <Badge variant="warning" icon={<IconClock className="size-3" aria-hidden />}>
          まもなく終了
        </Badge>
      );
    case "closed":
      return (
        <Badge variant="secondary" icon={<IconLock className="size-3" aria-hidden />}>
          営業時間外
        </Badge>
      );
  }
}
